fn validate_float_range<R>(s: &str, range: R) -> Result<f64, String>
where
    R: RangeBounds<f64> + Debug,
{
    let val: f64 = s
        .parse()
        .map_err(|_| format!("`{s}` isn't a valid number"))?;

    if (range).contains(&val) {
        Ok(val)
    } else {
        Err(format!("Value {val} is out of range (0.0..1.0)"))
    }
}

